using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "AppDatabase");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Session>(b =>
        {
            b.ToContainer("Sessions");

            // Fix 1: EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
            // Existing documents use "Discriminator", so we must preserve the old property name.
            b.HasDiscriminator<string>("Discriminator");

            // Fix 2: EF Core 9 no longer includes the discriminator in the JSON `id` property.
            // Existing documents have ids like "Session|abc123". Preserve the old format.
            b.HasRootDiscriminatorInJsonId(true);
        });
    }
}

// Fix 3: EF Core 9 Cosmos provider no longer supports synchronous I/O.
// All queries and saves must use async equivalents.
class CosmosSessionService
{
    private readonly CosmosDbContext _db;

    public CosmosSessionService(CosmosDbContext db) => _db = db;

    // Before (breaks in EF Core 9):
    //   var sessions = _db.Sessions.Where(s => s.IsActive).ToList();
    //   _db.SaveChanges();
    //
    // After: use async methods
    public async Task<List<Session>> GetActiveSessionsAsync()
    {
        return await _db.Sessions.Where(s => s.IsActive).ToListAsync();
    }

    public async Task SaveAsync()
    {
        await _db.SaveChangesAsync();
    }
}

class Session
{
    public string Id { get; set; } = string.Empty;
    public bool IsActive { get; set; }
}

